INSERT INTO public.clubs (id, announcement_topic_id, category, created_at, created_by, description, image, max_members, name, objective, registration_fee, review_comment, reviewed_by, status, suspended_at, suspended_by, suspension_reason, updated_at) VALUES (5, NULL, 'CONVERSATION', '2026-04-17 14:32:28.530748', 15, 'Club de débats structurés en anglais sur des sujets d''actualité, société, technologie et culture. Format organisé avec modérateur, arguments préparés et temps de parole équitable. Niveau intermédiaire à avancé recommandé.', NULL, 20, 'Debate & Discussion Club', 'Développer l''argumentation en anglais, apprendre à défendre ses idées avec clarté et respecter les opinions divergentes. Perfectionner l''expression orale formelle.', NULL, 'Club bien structuré avec des débats de qualité', 3, 'APPROVED', NULL, NULL, NULL, '2026-04-17 14:32:28.530748');
INSERT INTO public.clubs (id, announcement_topic_id, category, created_at, created_by, description, image, max_members, name, objective, registration_fee, review_comment, reviewed_by, status, suspended_at, suspended_by, suspension_reason, updated_at) VALUES (6, NULL, 'BOOK', '2026-04-17 14:32:28.530748', 19, 'Club de lecture dédié aux classiques de la littérature anglaise et américaine. Nous lisons un livre par mois (Shakespeare, Dickens, Austen, Hemingway...) et organisons des discussions approfondies sur les thèmes, personnages et contexte historique.', NULL, 30, 'Classic Literature Circle', 'Découvrir les grands classiques de la littérature anglophone, enrichir son vocabulaire littéraire et développer l''analyse critique en anglais.', NULL, 'Excellente initiative pour les amoureux de littérature', 3, 'APPROVED', NULL, NULL, NULL, '2026-04-17 14:32:28.530748');
INSERT INTO public.clubs (id, announcement_topic_id, category, created_at, created_by, description, image, max_members, name, objective, registration_fee, review_comment, reviewed_by, status, suspended_at, suspended_by, suspension_reason, updated_at) VALUES (7, NULL, 'BOOK', '2026-04-17 14:32:28.530748', 22, 'Club de lecture contemporaine explorant les best-sellers et romans modernes en anglais. Romans policiers, science-fiction, romance, thrillers... Discussions détendues et partage de recommandations entre passionnés.', NULL, 25, 'Modern Fiction Readers', 'Maintenir une pratique régulière de lecture en anglais, découvrir de nouveaux auteurs et partager le plaisir de lire dans un groupe dynamique.', NULL, 'Club actif avec de bonnes discussions', 3, 'APPROVED', NULL, NULL, NULL, '2026-04-17 14:32:28.530748');
